import { createProblemBrowserController } from './browserController.js';
import { createProblemCollectionController } from './collectionController.js';
import { createLeetcodeHotController } from './leetcodeHotController.js';

export function createProblemControllerBundle(deps = {}) {
  const collection = createProblemCollectionController({
    elements: deps.elements,
    documentRef: deps.documentRef,
    getState: deps.getState,
    getCatalogProblems: deps.getCatalogProblems,
    getFilterState: deps.getFilterState,
    getLanguage: deps.getLanguage,
    normalizeCategory: deps.normalizeCategory,
    formatCategoryLabel: deps.formatCategoryLabel,
    getCompletionCount: deps.getCompletionCount,
    getLeetcodeHotCompletionStats: deps.getLeetcodeHotCompletionStats,
    skillDefs: deps.skillDefs,
    isCatalogProblem: deps.isCatalogProblem,
    matchesSource: deps.matchesSource,
    isLeetcodeExpanded: deps.isLeetcodeExpanded,
    setLeetcodeExpanded: deps.setLeetcodeExpanded,
    renderLeetcodeHot100: deps.renderLeetcodeHot100,
    applyNavigationFilters: deps.applyNavigationFilters,
    resetPagination: deps.resetPagination,
    renderProblems: deps.renderProblems,
    t: deps.t
  });

  const leetcodeHotController = createLeetcodeHotController({
    elements: deps.elements,
    items: deps.leetcodeHotItems,
    getState: deps.getState,
    getLanguage: deps.getLanguage,
    normalizeDoneIds: deps.normalizeLeetcodeHot100Done,
    renderProblemCollectionGrid: collection.renderProblemCollectionGrid,
    saveState: deps.saveState,
    renderSummary: deps.renderSummary,
    renderProblemCompletionDashboard: collection.renderProblemCompletionDashboard,
    renderSkills: deps.renderSkills,
    refreshIcons: deps.refreshIcons,
    emptyBlock: deps.emptyBlock,
    t: deps.t
  });

  const browserController = createProblemBrowserController({
    elements: deps.elements,
    documentRef: deps.documentRef,
    windowRef: deps.windowRef,
    pageSize: deps.pageSize,
    getState: deps.getState,
    getFilterState: deps.getFilterState,
    getLanguage: deps.getLanguage,
    getLocale: deps.getLocale,
    getSearchQuery: deps.getSearchQuery,
    searchRecordCache: deps.searchRecordCache,
    tagLabels: deps.tagLabels,
    isCatalogProblem: deps.isCatalogProblem,
    matchesSource: deps.matchesSource,
    matchesCompany: deps.matchesCompany,
    matchesTheme: deps.matchesTheme,
    matchesDifficulty: deps.matchesDifficulty,
    getPersonalState: deps.getPersonalState,
    getDisplayTitle: deps.getDisplayTitle,
    getPromptText: deps.getPromptText,
    getSocial: deps.getSocial,
    getCompanies: deps.getCompanies,
    getCompanyAliases: deps.getCompanyAliases,
    formatCategory: deps.formatCategoryLabel,
    formatTag: deps.formatTag,
    isHiddenTag: deps.isHiddenTag,
    openProblemDetail: deps.openProblemDetail,
    toggleCompleted: deps.toggleCompleted,
    toggleSaved: deps.toggleSaved,
    emptyBlock: deps.emptyBlock,
    t: deps.t,
    cancelSearchRender: deps.cancelSearchRender,
    renderLeetcodeHot100: deps.renderLeetcodeHot100,
    renderProblemThemeFilter: collection.renderProblemThemeFilter,
    renderProblemDifficultyFilter: collection.renderProblemDifficultyFilter,
    renderProblemCompletionDashboard: collection.renderProblemCompletionDashboard,
    getSelectedDetailId: deps.getSelectedDetailId,
    setSelectedDetailId: deps.setSelectedDetailId,
    renderProblemDetail: deps.renderProblemDetail,
    hidePagination: deps.hidePagination,
    getPage: deps.getPage,
    setPage: deps.setPage,
    renderPagination: deps.renderPagination,
    refreshIcons: deps.refreshIcons,
    getCatalogProblems: deps.getCatalogProblems,
    companies: deps.companies,
    getCompanyFilter: deps.getCompanyFilter,
    getCompanyProblemStats: deps.getCompanyProblemStats,
    companyTierWeight: deps.companyTierWeight,
    createCompanyMark: deps.createCompanyMark,
    getSocialNotice: deps.getSocialNotice,
    getSourceLabel: deps.getSourceLabel,
    applyNavigationFilters: deps.applyNavigationFilters,
    resetPagination: deps.resetPagination
  });

  return {
    browserController,
    collectionController: collection,
    leetcodeHotController,
    getProblemThemeEntries: collection.getProblemThemeEntries,
    renderProblemThemeFilter: collection.renderProblemThemeFilter,
    renderProblemDifficultyFilter: collection.renderProblemDifficultyFilter,
    buildProblemProgressItems: collection.buildProblemProgressItems,
    renderProgressGroup: collection.renderProgressGroup,
    renderProblemCompletionDashboard: collection.renderProblemCompletionDashboard,
    getProblemCollectionEntries: collection.getProblemCollectionEntries,
    renderProblemCollectionGrid: collection.renderProblemCollectionGrid,
    handleProblemCollectionClick: collection.handleProblemCollectionClick
  };
}
